#include <vector>
#include <iostream>

using namespace std;

class Solution {
public:
    void push(int x, vector<int>& h) {
        h.push_back(x);
        _heapify_up(h, x);
    }

    void _heapify_up(vector<int>& h, int x) {
        int i = h.size() - 1;
        while (i > 0 && h[parent(i)] < x) {
            swap(h[i], h[parent(i)]);
            i = parent(i);
        }
    }

    int parent(int i) {
        return (i - 1) / 2;
    }

    int left(int i) {
        return 2 * i + 1;
    }

    int right(int i) {
        return 2 * i + 2;
    }

    void _heapify_down(vector<int>& h, int x) {
        int i = 0;
        while (true) {
            int left = left(i);
            int right = right(i);
            int largest = i;
            if (left < h.size() && h[left] > h[largest]) {
                largest = left;
            }
            if (right < h.size() && h[right] > h[largest]) {
                largest = right;
            }
            if (largest == i) {
                break;
            }
            h[i], h[largest] = h[largest], h[i];
            i = largest;
        }
    }

    void printHeap(vector<int>& h) {
        for (int i = 0; i < h.size(); i++) {
            cout << h[i] << " ";
        }
        cout << endl;
    }

    int main() {
        Solution solution;
        vector<int> h;
        solution.push(5, h);
        solution.push(10, h);
        solution.push(3, h);
        solution.push(1, h);
        solution.push(8, h);
        solution.printHeap(h);
        return 0;
    }
